# synthkits.py -- synthesized drum kits (DrumSynth-derived + Synth-Secrets
# recipes), the TR-8S-style alternative to the sampled Gamma9001 kits.
#
# Data lives in synthkits.json (generated by tools/drumsynth/make_synthkits.py
# from 1,000+ harvested .ds patches): a corpus of HITS (each <= 2 AMY oscs:
# tone + noise) and KITS mapping GM drum notes to hit keys. Each hit becomes
# its own tiny AMY synth at kit load, so per-hit sound design (tune/decay/
# level/snap) is just re-sending one synth's patch string -- no engine work.
#
# Import-clean on CPython (tulip/amy imported lazily) so tests can run on the
# host against the same JSON.

import json

_JSON_PATHS = ('/user/synthkits.json', 'synthkits.json')
_state = {'data': None}

# Deck-wide RAM-patch SLOT MAP (user patches 1024+). AMY stores every
# patch_string into a RAM slot and slots are never freed -- sending raw
# patch_string on each router rebuild leaked the pool dry. Deck code stores
# at EXPLICIT numbers instead (stores overwrite), then loads by number:
#   1024        audition scratch (this module)
#   1025..1029  melodic patch_string instruments by creation order (forwarder)
#   1030+24*n   drum kit instance n: kit patch at base, hits at base+1..
SLOT_AUDITION = 1024
SLOT_MELODIC = 1025
SLOT_KITS = 1030
SLOT_KIT_STRIDE = 24


def store_patch(slot, patch_string):
    """Store a patch string at an explicit reusable RAM slot."""
    import amy
    amy.send(patch=slot, patch_string=patch_string)
    return slot

# wire letters per osc kwarg (see amy parse.c); order chosen so envelopes
# arrive before amp
_WIRE = (('wave', 'w'), ('freq', 'f'), ('duty', 'd'), ('phase', 'P'),
         ('bp1', 'B'), ('bp0', 'A'), ('amp', 'a'), ('filter_type', 'G'),
         ('filter_freq', 'F'), ('resonance', 'R'))


def _load():
    if _state['data'] is None:
        for p in _JSON_PATHS:
            try:
                with open(p) as f:
                    _state['data'] = json.load(f)
                break
            except (OSError, ValueError):
                continue
        if _state['data'] is None:
            _state['data'] = {'hits': {}, 'kits': {}, 'packs': {}}
    return _state['data']


def kits():
    """{kit_key: display name}."""
    return {k: v['name'] for k, v in _load()['kits'].items()}


def kit_notes(kit_key):
    """{midi_note(int): hit_key} for a kit."""
    k = _load()['kits'].get(kit_key)
    return {int(n): h for n, h in k['notes'].items()} if k else {}


def hit_name(hit_key):
    h = _load()['hits'].get(hit_key)
    return h['name'] if h else hit_key


def pack_hits(pack):
    """Every hit key in a pack (for the picker/editor's alternates list)."""
    return list(_load()['packs'].get(pack, []))


def _fmt(x):
    if isinstance(x, str):
        return x
    if abs(x - round(x)) < 0.005:
        return '%d' % round(x)
    return ('%.3f' % x).rstrip('0').rstrip('.')


def _scale_times(bp, factor):
    """Scale a bp string's TIME entries (even slots) by factor."""
    vals = bp.split(',')
    out = []
    for i, v in enumerate(vals):
        if i % 2 == 0:
            try:
                out.append('%d' % max(0, round(float(v) * factor)))
            except ValueError:
                out.append(v)
        else:
            out.append(v)
    return ','.join(out)


def _scale_first(csv, factor):
    """Scale the first (const) slot of a coef string."""
    vals = csv.split(',')
    try:
        vals[0] = _fmt(float(vals[0]) * factor)
    except ValueError:
        pass
    return ','.join(vals)


def hit_patch_string(hit_key, overrides=None):
    """AMY patch wire string for one hit ('v0...Zv1...Z'), with sound-design
    overrides applied: tune (semitones, +/-24), decay (0.25..4 time scale),
    level (0..2 gain), snap (0..2 gain on the noise/transient osc)."""
    hit = _load()['hits'].get(hit_key)
    if hit is None:
        raise KeyError(hit_key)
    ov = overrides or {}
    tune = 2.0 ** (max(-24.0, min(24.0, float(ov.get('tune', 0)))) / 12.0)
    decay = max(0.25, min(4.0, float(ov.get('decay', 1.0))))
    level = max(0.0, min(2.0, float(ov.get('level', 1.0))))
    snap = max(0.0, min(2.0, float(ov.get('snap', 1.0))))
    parts = []
    for i, osc in enumerate(hit['oscs'][:2]):
        o = dict(osc)
        if 'freq' in o and tune != 1.0:
            o['freq'] = _scale_first(o['freq'], tune)
        if 'filter_freq' in o and tune != 1.0:
            o['filter_freq'] = _scale_first(str(o['filter_freq']), tune)
        if decay != 1.0:
            for bp in ('bp0', 'bp1'):
                if bp in o:
                    o[bp] = _scale_times(o[bp], decay)
        g = level * (snap if o.get('wave') == 5 else 1.0)   # 5 = NOISE
        if g != 1.0 and 'amp' in o:
            o['amp'] = _scale_first(o['amp'], g)
        frag = ['v%d' % i]
        for key, letter in _WIRE:
            if key in o:
                frag.append(letter + _fmt(o[key]))
        parts.append(''.join(frag))
    return 'Z'.join(parts) + 'Z'


def audition(hit_key, overrides=None, note=60, vel=1.0, synth=15):
    """Play one hit immediately (editor preview). Uses a scratch synth.
    (patch_string implies the osc count -- passing oscs_per_voice alongside
    it makes AMY ignore the stored patch.)"""
    import amy
    store_patch(SLOT_AUDITION, hit_patch_string(hit_key, overrides))
    amy.send(synth=synth, num_voices=0)   # release: a re-patch on a live
    amy.send(synth=synth, num_voices=1,   # synth keeps its old config
             patch=SLOT_AUDITION)
    amy.send(synth=synth, note=note, vel=vel)
